import { useWallpaper, ACCENT_COLORS } from '../../contexts/WallpaperContext'

function AppearanceSettings() {
    const { theme, setTheme, accentColor, setAccentColor } = useWallpaper()

    return (
        <div className="settings-appearance">
            <h3 className="settings-section-title">Appearance</h3>

            {/* Theme Selector */}
            <div className="settings-group">
                <label className="settings-group-label">Theme</label>
                <div className="theme-selector">
                    {[
                        { id: 'auto', label: 'Auto' },
                        { id: 'light', label: 'Light' },
                        { id: 'dark', label: 'Dark' },
                    ].map(t => (
                        <div
                            key={t.id}
                            className={`theme-option ${theme === t.id ? 'active' : ''}`}
                            onClick={() => setTheme(t.id)}
                        >
                            <div className={`theme-preview theme-preview-${t.id}`}>
                                <div className="theme-preview-bar"></div>
                                <div className="theme-preview-content">
                                    <div className="theme-preview-sidebar"></div>
                                    <div className="theme-preview-main"></div>
                                </div>
                            </div>
                            <span className="theme-option-label">{t.label}</span>
                        </div>
                    ))}
                </div>
            </div>

            <div className="settings-divider"></div>

            {/* Accent Color Picker */}
            <div className="settings-group">
                <label className="settings-group-label">Accent Color</label>
                <div className="accent-color-row">
                    {ACCENT_COLORS.map(color => (
                        <button
                            key={color.id}
                            className={`accent-dot ${accentColor.id === color.id ? 'active' : ''}`}
                            style={{ background: color.value }}
                            onClick={() => setAccentColor(color)}
                            title={color.label}
                        >
                            {accentColor.id === color.id && (
                                <span className="accent-dot-check">✓</span>
                            )}
                        </button>
                    ))}
                </div>
                <div className="accent-color-label">{accentColor.label}</div>
            </div>
        </div>
    )
}

export default AppearanceSettings
